1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Array<Item> };
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Array<QuoteStep> };
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const premiumFor = (item: Item): number => {
17	  const base = BASE_PREMIUMS[item.type];
18	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
19	  return base + firstInsuranceSurcharge;
20	};
21	
22	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	const BLOCK_SIZE = 3;
26	const BLOCK_PREMIUM = 60;
27	
28	const componentBaseFor = (items: Item[]): number => {
29	  const counts: Record<string, number> = {};
30	  for (const item of items) {
31	    if (COMPONENT_TYPES.has(item.type)) {
32	      counts[item.type] = (counts[item.type] ?? 0) + 1;
33	    }
34	  }
35	  let total = 0;
36	  for (const type of Object.keys(counts)) {
37	    const count = counts[type];
38	    const blocks = Math.floor(count / BLOCK_SIZE);
39	    const remainder = count % BLOCK_SIZE;
40	    // Block only applies for exactly 3; if exactly 3, use block premium; otherwise no block discount
41	    if (count === BLOCK_SIZE) {
42	      total += BLOCK_PREMIUM;
43	    } else {
44	      total += count * BASE_PREMIUMS[type];
45	    }
46	    void blocks;
47	    void remainder;
48	  }
49	  return total;
50	};
51	
52	const quotePremium = (step: QuoteStep): number => {
53	  const mainItems = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
54	  const componentItems = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
55	  const mainBase = sum(mainItems.map((i) => BASE_PREMIUMS[i.type]));
56	  const componentBase = componentBaseFor(componentItems);
57	  const policyBase = mainBase + componentBase;
58	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
59	  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
60	};
61	
62	export const runScenario = (input: unknown): unknown => {
63	  const scenario = input as Scenario;
64	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
65	  return { results };
66	};
