const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const componentTypeBase = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];

const componentBaseFor = (items: Item[]): number => {
  const counts = countByType(items);
  return sum(Object.keys(counts).map((type) => componentTypeBase(type, counts[type])));
};

